/* tms-item-itemgroup-sql-oracle.xml - insertTTMstIcgr */
/* Converted from: MERGE INTO TT_MST_ICGR ON CONFLICT */
INSERT INTO TT_MST_ICGR (
		 UPDATEURKEY, UPDATEDATE, INSERTURKEY, INSERTDATE
		,ICGRTYPE, ICGRNAME, ICGRKEY, CLOSDATE, OWKEY, SAMFILENAME
	) VALUES (
		 #{surkey}, #{sysdate}, #{surkey}, #{sysdate}
		,#{icgrtype}, #{icgrname}, #{icgrkey}, SUBSTR(#{closdate}, 0, 14), #{owkey}, #{samfilename}
	)
ON CONFLICT (OWKEY, ICGRKEY, ICGRTYPE) DO UPDATE SET
		 UPDATEURKEY = #{surkey}
		,UPDATEDATE  = #{sysdate}
		,ICGRNAME    = #{icgrname}
		,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
		,SAMFILENAME = #{samfilename}

mapper.update:
		/* tms-item-itemgroup-sql-oracle.xml - updateTTMstIcgr */
		UPDATE 	TT_MST_ICGR 
		SET		UPDATEURKEY = #{surkey}
				,UPDATEDATE  = #{sysdate}
				,ICGRNAME    = #{icgrname}
				,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
				,SAMFILENAME = #{samfilename}   
	    WHERE 	OWKEY = #{owkey}
    	AND 	ICGRKEY = #{icgrkey}
        AND 	ICGRTYPE = #{icgrtype}

mapper.delete:
		/* tms-item-itemgroup-sql-oracle.xml - deleteTTMstIcgr */
		DELETE
		FROM 	TT_MST_ICGR	
 	    WHERE 	OWKEY = #{owkey}
	    AND  	ICGRKEY = #{icgrkey}
        AND 	ICGRTYPE = #{icgrtype}

